  <div class="es">
  <svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Comparación de Políticas Bancarias de Wall Street sobre Apuestas en Mercados de Predicción</text>
    <g font-family="sans-serif">
      <text x="20" y="55" fill="#a1a1aa" font-size="14" font-weight="700">① Comparación de Políticas por Banco</text>
      <circle cx="32" cy="82" r="8" fill="#ef4444"/>
      <text x="52" y="87" fill="#fafafa" font-size="14" font-weight="700">Goldman Sachs</text>
      <text x="52" y="105" fill="#a1a1aa" font-size="13">Prohibición explícita: empresas, elecciones, datos macro, geopolítica</text>
      <text x="52" y="121" fill="#a1a1aa" font-size="13">Reincidencia → despido · recupera ganancias sobre $200</text>
      <circle cx="32" cy="148" r="8" fill="#fbbf24"/>
      <text x="52" y="153" fill="#fafafa" font-size="14" font-weight="700">Morgan Stanley</text>
      <text x="52" y="171" fill="#a1a1aa" font-size="13">Solo añadió lenguaje al código de conducta</text>
      <text x="52" y="187" fill="#a1a1aa" font-size="13">Categorías específicas no reveladas</text>
      <circle cx="32" cy="214" r="8" fill="#fb923c"/>
      <text x="52" y="219" fill="#fafafa" font-size="14" font-weight="700">Bank of America</text>
      <text x="52" y="237" fill="#a1a1aa" font-size="13">Implementando restricciones internas para el personal</text>
